+      id: 'user-1',
+      name: 'Alice',
+      email: 'alice@example.com',
+      role: 'member',
+      createdAt: new Date(),
+      updatedAt: new Date(),
+    },
+    timestamp: new Date(),
+    ...overrides,
+  };
